// src/views/VisitorProfile.js - بروفيل الزائر (مع استخدام المكونات المشتركة)
import React, { useState } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";
import SocialFooter from "components/Common/socialFooter";
import RestaurantCard from "components/Common/restaurantCard";
import EmployeeCard from "components/Common/employecard";

export default function VisitorProfile() {
  // ==================== بيانات البروفيل ====================
  const [visitorInfo, setVisitorInfo] = useState({
    name: "Restaurant Andalous",
    role: "Restaurant Gastronomique",
    experience: "Ouvert depuis 2010",
    skills: ["Cuisine Algérienne", "Plats Internationaux", "Pâtisserie Orientale", "Service de Qualité"],
    bio: "Bienvenue dans notre établissement! Nous sommes fiers de vous offrir une expérience culinaire unique dans une ambiance chaleureuse et familiale.",
    email: "contact@andalus-restaurant.dz",
    phone: "+213 5 55 55 55 55",
    location: "Alger, Algérie",
    languages: ["Français", "Arabe", "Anglais"]
  });
  
  // ==================== بيانات المطعم (كرت المطعم) ====================
  const [restaurantCardData, setRestaurantCardData] = useState({
    id: 1,
    name: "Restaurant Andalous",
    location: "Alger, Algérie",
    description: "Les meilleurs plats arabes et internationaux dans une ambiance familiale",
    image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
    phone: "+213 5 55 55 55 55",
    email: "info@andalus-restaurant.dz",
    rating: 4.8,
    employees: 12,
    horaires: "Lundi - Dimanche: 10h00 - 23h00"
  });
  
  // ==================== بيانات المنيو ====================
  const [menuCategories, setMenuCategories] = useState([
    { id: 1, name: "Chicha", icon: "💨", color: "#ff6b6b", products: [
      { id: 101, name: "Chicha Pomme", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 102, name: "Chicha Raisin", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 103, name: "Chicha Menthe", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" }
    ] },
    { id: 2, name: "Plats", icon: "🍔", color: "#4ecdc4", products: [
      { id: 201, name: "Burger", price: 12, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
      { id: 202, name: "Pizza", price: 18, image: "https://cdn-icons-png.flaticon.com/512/1046/1046796.png" }
    ] },
    { id: 3, name: "Boissons", icon: "🥤", color: "#45b7d1", products: [
      { id: 301, name: "Coca Cola", price: 3, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
      { id: 302, name: "Jus d'Orange", price: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" }
    ] },
    { id: 4, name: "Desserts", icon: "🍰", color: "#f9ca24", products: [
      { id: 401, name: "Gâteau", price: 7, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
      { id: 402, name: "Glace", price: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046800.png" }
    ] }
  ]);
  
  // ==================== بيانات العمال ====================
  const [employees, setEmployees] = useState([
    { id: 1, name: "Youssef", role: "Serveur", location: "Alger, Algérie", bio: "Serveur professionnel avec 3 ans d'expérience", image: "https://randomuser.me/api/portraits/men/1.jpg", experience: "3 ans", rating: 4.5, restaurant: "Restaurant Andalous" },
    { id: 2, name: "Mohamed", role: "Chef Cuisinier", location: "Alger, Algérie", bio: "Chef cuisinier passionné avec 8 ans d'expérience", image: "https://randomuser.me/api/portraits/men/2.jpg", experience: "8 ans", rating: 4.9, restaurant: "Restaurant Andalous" },
    { id: 3, name: "Karim", role: "Barman", location: "Alger, Algérie", bio: "Barman créatif, spécialisé dans les cocktails", image: "https://randomuser.me/api/portraits/men/3.jpg", experience: "4 ans", rating: 4.4, restaurant: "Restaurant Andalous" },
    { id: 4, name: "Sophie", role: "Serveuse", location: "Paris, France", bio: "Serveuse expérimentée", image: "https://randomuser.me/api/portraits/women/1.jpg", experience: "2 ans", rating: 4.6, restaurant: "Café Parisien" },
    { id: 5, name: "Amine", role: "Pâtissier", location: "Alger, Algérie", bio: "Pâtissier expert", image: "https://randomuser.me/api/portraits/men/4.jpg", experience: "6 ans", rating: 4.7, restaurant: "Restaurant Andalous" }
  ]);
  
  // ==================== SOCIAL LINKS ====================
  const [socialLinks, setSocialLinks] = useState({
    facebook: "",
    instagram: "",
    twitter: "",
    linkedin: "",
    tiktok: ""
  });
  
  // ==================== STATES للمودالات ====================
  const [showRestaurantModal, setShowRestaurantModal] = useState(false);
  const [showMenuModal, setShowMenuModal] = useState(false);
  const [showWorkersModal, setShowWorkersModal] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);
  const [selectedEmployee, setSelectedEmployee] = useState(null);
  
  // ==================== STATES للطلب ====================
  const [orderActive, setOrderActive] = useState({});
  const [quantities, setQuantities] = useState({});
  
  // ==================== FUNCTIONS للطلب ====================
  const startOrder = (productId) => {
    setOrderActive({ ...orderActive, [productId]: true });
    setQuantities({ ...quantities, [productId]: 1 });
  };
  
  const increaseQty = (productId) => {
    setQuantities({ ...quantities, [productId]: (quantities[productId] || 1) + 1 });
  };
  
  const decreaseQty = (productId) => {
    if (quantities[productId] > 1) {
      setQuantities({ ...quantities, [productId]: quantities[productId] - 1 });
    }
  };
  
  const confirmOrder = (productName, productId, qty, price) => {
    alert(`✅ Commande confirmée : ${qty} × ${productName}\n💰 Total : ${qty * price} DA`);
    setOrderActive({ ...orderActive, [productId]: false });
    setQuantities({ ...quantities, [productId]: 1 });
  };
  
  // ==================== STYLES ====================
  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes shoot {
      0% { transform: translateX(0) translateY(0) rotate(45deg); opacity: 0; }
      5% { opacity: 1; }
      95% { opacity: 1; }
      100% { transform: translateX(-300px) translateY(300px) rotate(45deg); opacity: 0; }
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    @keyframes gradient-border {
      0% { background-position: 0% 0%; }
      50% { background-position: 400% 0%; }
      100% { background-position: 0% 0%; }
    }
    
    @keyframes borderPulse {
      0%, 100% { opacity: 0.6; filter: blur(8px); }
      50% { opacity: 1; filter: blur(12px); }
    }
    
    @keyframes rainbowLine {
      0% { background-position: 0% 50%; }
      100% { background-position: 200% 50%; }
    }
    
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    @keyframes float {
      0%, 100% { transform: translateY(0px) translateX(0px); }
      25% { transform: translateY(-8px) translateX(4px); }
      75% { transform: translateY(8px) translateX(-4px); }
    }
    
    @keyframes shine {
      0% { transform: translate(-30%, -30%) rotate(0deg); }
      100% { transform: translate(30%, 30%) rotate(180deg); }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
      padding-top: 80px;
    }
    
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    .shooting-star {
      position: absolute;
      width: 2px;
      height: 2px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,255,0) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2s ease-out infinite;
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-position: center 30%;
      background-size: cover;
      filter: brightness(0.85) contrast(1.05);
      transition: transform 0.5s ease;
    }
    
    .hero-image:hover {
      transform: scale(1.01);
    }
    
    .hero-overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%);
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
      box-shadow: 0 20px 40px rgba(0, 0, 0, 0.2);
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    .gradient-border-box .content {
      width: calc(100% - 4px);
      height: calc(100% - 4px);
      background-size: cover;
      background-position: center;
      border-radius: 50%;
      box-shadow: 0 0 30px rgba(0,0,0,0.3);
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    .action-buttons {
      display: flex;
      justify-content: center;
      gap: 15px;
      margin-top: 20px;
      margin-bottom: 20px;
    }
    
    .btn-contact {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 14px;
    }
    
    .btn-contact:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    .btn-comment {
      background: linear-gradient(135deg, #ff6b6b, #f5576c);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 14px;
    }
    
    .btn-comment:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(255,107,107,0.4);
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
      background: #22c55e;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      border: 1px solid rgba(34,197,94,0.4);
      backdrop-filter: blur(5px);
    }
    
    /* ========== Styles des 3 cartes pour le visiteur ========== */
    .visitor-cards-container {
      display: flex;
      gap: 30px;
      justify-content: center;
      margin-top: 40px;
      flex-wrap: wrap;
      position: relative;
      padding-bottom: 30px;
      z-index: 5;
    }
    
    .visitor-cards-container::after {
      content: '';
      position: absolute;
      bottom: -15px;
      left: 10%;
      width: 80%;
      height: 4px;
      background: linear-gradient(90deg, transparent, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000, transparent);
      background-size: 200% 100%;
      border-radius: 4px;
      animation: rainbowLine 3s linear infinite;
    }
    
    .visitor-card {
      flex: 1;
      min-width: 280px;
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 35px 25px;
      cursor: pointer;
      transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      text-align: center;
      position: relative;
      overflow: hidden;
      animation: float 4s ease-in-out infinite;
      z-index: 5;
    }
    
    .visitor-card:nth-child(1) {
      background: linear-gradient(135deg, #FF6B6B 0%, #FF8E53 50%, #FF6B6B 100%);
      background-size: 200% 200%;
      box-shadow: 0 15px 35px rgba(255, 107, 107, 0.3);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 0s;
    }
    
    .visitor-card:nth-child(1):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 25px 45px rgba(255, 107, 107, 0.5);
    }
    
    .visitor-card:nth-child(2) {
      background: linear-gradient(135deg, #4ECDC4 0%, #556270 50%, #4ECDC4 100%);
      background-size: 200% 200%;
      box-shadow: 0 15px 35px rgba(78, 205, 196, 0.3);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 0.5s;
    }
    
    .visitor-card:nth-child(2):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 25px 45px rgba(78, 205, 196, 0.5);
    }
    
    .visitor-card:nth-child(3) {
      background: linear-gradient(135deg, #A8E6CF 0%, #3E92CC 50%, #A8E6CF 100%);
      background-size: 200% 200%;
      box-shadow: 0 15px 35px rgba(62, 146, 204, 0.3);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 1s;
    }
    
    .visitor-card:nth-child(3):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 25px 45px rgba(62, 146, 204, 0.5);
    }
    
    .visitor-card::before {
      content: '';
      position: absolute;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: radial-gradient(circle, rgba(255,255,255,0.3) 0%, rgba(255,255,255,0) 70%);
      opacity: 0;
      transition: opacity 0.6s;
      pointer-events: none;
    }
    
    .visitor-card:hover::before {
      opacity: 1;
      animation: shine 1.5s;
    }
    
    /* ========== Styles des modales ========== */
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.95);
      backdrop-filter: blur(12px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 600px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      animation: fadeIn 0.4s ease;
    }
    
    .modal-content-large {
      max-width: 900px;
    }
    
    .close-btn {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .close-btn:hover {
      transform: scale(1.1);
      color: #ef4444;
    }
    
    .restaurant-info {
      text-align: center;
    }
    
    .restaurant-logo {
      width: 100px;
      height: 100px;
      border-radius: 50%;
      margin-bottom: 15px;
    }
    
    .restaurant-image {
      width: 100%;
      height: 200px;
      object-fit: cover;
      border-radius: 20px;
      margin: 15px 0;
    }
    
    .menu-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
      gap: 20px;
      margin-top: 20px;
    }
    
    .category-card {
      background: rgba(0,0,0,0.4);
      border-radius: 20px;
      padding: 20px;
      cursor: pointer;
      transition: all 0.3s;
      text-align: center;
    }
    
    .category-card:hover {
      transform: scale(1.02);
      background: rgba(0,0,0,0.6);
    }
    
    .products-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 15px;
      margin-top: 20px;
    }
    
    .product-card {
      background: rgba(255,255,255,0.1);
      border-radius: 15px;
      padding: 15px;
      text-align: center;
      transition: all 0.3s;
    }
    
    .product-card:hover {
      transform: translateY(-5px);
      background: rgba(255,255,255,0.15);
    }
    
    .product-image {
      width: 80px;
      height: 80px;
      object-fit: cover;
      border-radius: 15px;
      margin-bottom: 10px;
    }
    
    .product-price {
      color: #22c55e;
      font-weight: bold;
      margin: 10px 0;
    }
    
    .quantity-controls {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 15px;
      margin: 10px 0;
    }
    
    .quantity-btn {
      background: #22c55e;
      border: none;
      width: 30px;
      height: 30px;
      border-radius: 50%;
      color: white;
      font-size: 1.2rem;
      cursor: pointer;
    }
    
    .quantity-btn.minus {
      background: #ef4444;
    }
    
    .workers-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
      gap: 20px;
      margin-top: 20px;
    }
    
    .btn-order {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 8px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      margin-top: 10px;
      width: 100%;
    }
    
    .btn-order:hover {
      transform: scale(1.02);
    }
    
    @media (max-width: 768px) {
      .visitor-cards-container {
        flex-direction: column;
        gap: 20px;
        padding: 15px;
      }
      
      .visitor-cards-container::after {
        width: 90%;
        left: 5%;
        bottom: -10px;
      }
      
      .gradient-border-box {
        width: 120px;
        height: 120px;
        margin-top: -50px;
        margin-left: 0;
      }
      
      .action-buttons {
        flex-direction: column;
        gap: 10px;
        align-items: center;
      }
      
      .workers-grid {
        grid-template-columns: 1fr;
      }
      
      .menu-grid {
        grid-template-columns: 1fr;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="profile-hero-section">
        <div className="shooting-stars">
          {[...Array(60)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`
            }} />
          ))}
          {[...Array(10)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 40}%`,
              width: `${Math.random() * 60 + 40}px`,
              height: '2px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,255,150,0.8) 30%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: 'relative', overflow: 'hidden' }}>
            <div className="hero-image" style={{ 
              backgroundImage: "url('https://images.unsplash.com/photo-1517248135467-4c7edcad34c4')",
              backgroundSize: 'cover',
              backgroundPosition: 'center 40%'
            }}></div>
            <div className="hero-overlay"></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  
                  {/* صورة البروفيل الدائرية (لوجو المطعم) */}
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper" style={{ position: 'relative' }}>
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt="Restaurant Logo" src={restaurantCardData.logo} className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  {/* معلومات المطعم */}
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">
                      {restaurantCardData.name}
                      <span className="status-badge">⭐ Restaurant</span>
                    </h3>
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {restaurantCardData.location}
                    </div>
                    <div className="mb-2 text-gray-300 mt-10">
                      <i className="fas fa-star mr-2 text-green-400"></i> {visitorInfo.role}
                    </div>
                    <div className="mb-2 text-gray-300">
                      <i className="fas fa-clock mr-2 text-green-400"></i> {restaurantCardData.horaires}
                    </div>
                  </div>
                  
                  {/* أزرار الاتصال */}
                  <div className="action-buttons">
                    <button className="btn-contact" onClick={() => alert(`📧 Email: ${restaurantCardData.email}\n📱 Téléphone: ${restaurantCardData.phone}`)}>
                      📧 Contacter
                    </button>
                    <button className="btn-comment" onClick={() => setShowRestaurantModal(true)}>
                      📖 Découvrir
                    </button>
                  </div>
                  
                  {/* ========== 3 Cartes pour le visiteur ========== */}
                  <div className="visitor-cards-container">
                    
                    {/* Carte 1: Restaurant - Utilisation de RestaurantCard */}
                    <div className="visitor-card" onClick={() => setShowRestaurantModal(true)}>
                      <RestaurantCard 
                        restaurant={restaurantCardData}
                        showActions={false}
                      />
                    </div>
                    
                    {/* Carte 2: Menu */}
                    <div className="visitor-card" onClick={() => setShowMenuModal(true)}>
                      <div className="text-6xl mb-4">🍽️</div>
                      <h3 className="text-xl font-bold text-white mb-2">Notre Menu</h3>
                      <p className="text-white/90 text-sm">Découvrez nos délicieux plats, boissons et desserts</p>
                      <div className="mt-4 text-white/80 font-semibold">Cliquez pour commander →</div>
                    </div>
                    
                    {/* Carte 3: Équipe */}
                    <div className="visitor-card" onClick={() => setShowWorkersModal(true)}>
                      <div className="text-6xl mb-4">👨‍🍳</div>
                      <h3 className="text-xl font-bold text-white mb-2">Notre Équipe</h3>
                      <p className="text-white/90 text-sm">Rencontrez nos professionnels passionnés</p>
                      <div className="mt-4 text-white/80 font-semibold">Cliquez pour voir →</div>
                    </div>
                    
                  </div>
                  
                  {/* السيرة الذاتية والمهارات */}
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{visitorInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {visitorInfo.skills.map((skill, i) => (<span key={i} className="skill-tag">{skill}</span>))}
                        </div>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {visitorInfo.languages.map((lang, i) => (<span key={i} className="skill-tag">🌐 {lang}</span>))}
                        </div>
                      </div>
                    </div>
                  </div>
                  
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* ========== MODALS ========== */}
      
      {/* Modal Restaurant Détails */}
      {showRestaurantModal && (
        <div className="modal-overlay" onClick={() => setShowRestaurantModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="close-btn" onClick={() => setShowRestaurantModal(false)}>✕</button>
            <div className="restaurant-info">
              <div className="text-6xl mb-4">🏪</div>
              <h2 className="text-2xl font-bold text-white mb-2">{restaurantCardData.name}</h2>
              <div className="w-16 h-0.5 bg-green-500 mx-auto mb-6"></div>
              <img src={restaurantCardData.image} alt="restaurant" className="restaurant-image" />
              <p className="text-gray-300 mb-4">{restaurantCardData.description}</p>
              <p className="text-gray-400 text-sm">📍 {restaurantCardData.location}</p>
              <p className="text-gray-400 text-sm">📞 {restaurantCardData.phone}</p>
              <p className="text-gray-400 text-sm">✉️ {restaurantCardData.email}</p>
              <p className="text-gray-400 text-sm">🕐 {restaurantCardData.horaires}</p>
              <div className="mt-4">
                <h4 className="text-white font-bold mb-2">Nos spécialités</h4>
                <div className="flex flex-wrap gap-2 justify-center">
                  {visitorInfo.skills.map((spec, i) => (<span key={i} className="skill-tag">{spec}</span>))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* Modal Menu - Categories */}
      {showMenuModal && (
        <div className="modal-overlay" onClick={() => setShowMenuModal(false)}>
          <div className="modal-content modal-content-large" onClick={(e) => e.stopPropagation()}>
            <button className="close-btn" onClick={() => setShowMenuModal(false)}>✕</button>
            <div className="text-center">
              <div className="text-6xl mb-4">🍽️</div>
              <h2 className="text-3xl font-bold text-white mb-2">Notre Menu</h2>
              <div className="w-20 h-1 bg-green-500 mx-auto mb-6"></div>
              <p className="text-gray-300 mb-6">Découvrez nos délicieuses catégories</p>
            </div>
            
            <div className="menu-grid">
              {menuCategories.map(cat => (
                <div key={cat.id} className="category-card" onClick={() => setSelectedCategory(cat)}>
                  <div className="text-5xl mb-3">{cat.icon}</div>
                  <h3 className="text-xl font-bold text-white">{cat.name}</h3>
                  <p className="text-gray-400 text-sm mt-2">{cat.products.length} produits</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      
      {/* Modal Products by Category */}
      {selectedCategory && (
        <div className="modal-overlay" onClick={() => setSelectedCategory(null)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="close-btn" onClick={() => setSelectedCategory(null)}>✕</button>
            <div className="text-center">
              <div className="text-5xl mb-3">{selectedCategory.icon}</div>
              <h2 className="text-2xl font-bold text-white mb-2">{selectedCategory.name}</h2>
              <div className="w-16 h-0.5 bg-green-500 mx-auto mb-6"></div>
            </div>
            
            <div className="products-grid">
              {selectedCategory.products.map(product => {
                const isActive = orderActive[product.id];
                const qty = quantities[product.id] || 1;
                
                return (
                  <div key={product.id} className="product-card">
                    <img src={product.image} alt={product.name} className="product-image" />
                    <h4 className="text-white font-bold">{product.name}</h4>
                    <div className="product-price">{product.price} DA</div>
                    
                    {!isActive ? (
                      <button className="btn-order" onClick={() => startOrder(product.id)}>
                        🛒 Commander
                      </button>
                    ) : (
                      <div>
                        <div className="quantity-controls">
                          <button className="quantity-btn minus" onClick={() => decreaseQty(product.id)}>−</button>
                          <span className="text-white text-xl font-bold">{qty}</span>
                          <button className="quantity-btn" onClick={() => increaseQty(product.id)}>+</button>
                        </div>
                        <div className="text-green-400 mb-2">Total: {qty * product.price} DA</div>
                        <button className="btn-order" onClick={() => confirmOrder(product.name, product.id, qty, product.price)}>
                          ✓ Confirmer
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
      
      {/* Modal Workers - Utilisation de EmployeeCard */}
      {showWorkersModal && (
        <div className="modal-overlay" onClick={() => setShowWorkersModal(false)}>
          <div className="modal-content modal-content-large" onClick={(e) => e.stopPropagation()}>
            <button className="close-btn" onClick={() => setShowWorkersModal(false)}>✕</button>
            <div className="text-center">
              <div className="text-6xl mb-4">👨‍🍳</div>
              <h2 className="text-3xl font-bold text-white mb-2">Notre Équipe</h2>
              <div className="w-20 h-1 bg-green-500 mx-auto mb-6"></div>
              <p className="text-gray-300 mb-6">Des professionnels passionnés à votre service</p>
            </div>
            
            <div className="workers-grid">
              {employees.map(worker => (
                <EmployeeCard 
                  key={worker.id}
                  employee={worker}
                  showActions={false}
                />
              ))}
            </div>
          </div>
        </div>
      )}
      
      <SocialFooter socialLinks={socialLinks} />
      <Footer />
    </>
  );
}
